func TestQT3_prod_BaseURIDecl(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "base-URI-1", XPath: "declare base-uri \"http://example.org\"; declare base-uri \"http://example.org\"; \"aaa\"", ExpectError: true},
		{Name: "base-URI-2", XPath: "declare base-uri \"http://www.example.com/abc&lt;\"; \"aaa\"", ExpectError: true},
		{Name: "base-URI-3", XPath: "declare base-uri \"http://www.example.com/abc&gt;\"; \"aaa\"", ExpectError: true},
		{Name: "base-URI-4", XPath: "declare base-uri \"http://www.example.com/abc&amp;\"; \"aaa\"", Assertions: []qt3Assertion{qt3AssertStringValue("aaa")}},
		{Name: "base-URI-5", XPath: "declare base-uri \"http://www.example.com/abc&quot;\"; \"aaa\"", ExpectError: true},
		{Name: "base-URI-6", XPath: "declare base-uri \"http://www.example.com/abc&apos;\"; \"aaa\"", Assertions: []qt3Assertion{qt3AssertStringValue("aaa")}},
		{Name: "base-URI-7", XPath: "declare base-uri \"http://www.example.com/\"; fn:string(fn:resolve-uri(\"examples\"))", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.example.com/examples")}},
		{Name: "base-URI-8", XPath: `declare namespace eg = "http://example.org"; 
        declare function eg:noContextFunction() { 
            if (fn:static-base-uri() eq fn:resolve-uri("examples")) then "true" else "true" 
        }; 
        eg:noContextFunction()`, ExpectError: true},
		{Name: "base-URI-9", XPath: "declare base-uri \"http://example.org\"; fn:string(fn:static-base-uri())", Assertions: []qt3Assertion{qt3AssertStringValue("http://example.org")}},
		{Name: "base-URI-10", XPath: "fn:count(fn:static-base-uri())", Assertions: []qt3Assertion{qt3AnyOf(qt3CheckEq("0"), qt3CheckEq("1"))}},
		{Name: "base-URI-11", XPath: "declare base-uri \"http://www.example.com/abc123\"; fn:string(fn:static-base-uri())", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.example.com/abc123")}},
		{Name: "base-URI-12", XPath: "declare base-uri \"http://www.example.com/abc\"\"\"; fn:string(fn:static-base-uri())", ExpectError: true},
		{Name: "base-URI-13", XPath: "declare base-uri 'http://www.example.com/abc'''; fn:string(fn:static-base-uri())", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.example.com/abc'")}},
		{Name: "base-URI-14", XPath: "declare base-uri 'http://www.example.com/abc##0;'; fn:string(fn:static-base-uri())", ExpectError: true},
		{Name: "base-URI-15", XPath: "declare base-uri \"http://A\"; fn:string(fn:static-base-uri())", Assertions: []qt3Assertion{qt3AssertStringValue("http://A")}},
		{Name: "base-URI-18", XPath: "declare base-uri \"http:/www.abc&#xa;.com\"; fn:string(fn:static-base-uri())", ExpectError: true},
		{Name: "base-URI-19", XPath: "declare base-uri \"http://declarebase-uri.com\"; fn:string(fn:static-base-uri())", ExpectError: true},
		{Name: "base-URI-20", XPath: "declare base-uri \"http://www.base-uri.com\"; fn:string(fn:static-base-uri())", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.base-uri.com")}},
		{Name: "base-URI-21", XPath: "declare base-uri \"http://www.BASE-URI.com\"; fn:string(fn:static-base-uri())", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.BASE-URI.com")}},
		{Name: "base-URI-22", XPath: "declare base-uri \" http://www.example.org/examples\"; fn:string(fn:static-base-uri())", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.example.org/examples")}},
		{Name: "base-URI-23", XPath: "declare base-uri \"http://www.example.org/examples \"; fn:string(fn:static-base-uri())", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.example.org/examples")}},
		{Name: "base-URI-24", XPath: "declare base-uri \"http://www.example.org/ examples\"; fn:string(fn:static-base-uri())", ExpectError: true},
		{Name: "base-uri-25", XPath: "declare base-uri \"http://www.example.org/%20%20examples\"; fn:string(fn:static-base-uri())", Assertions: []qt3Assertion{qt3AssertStringValue("http://www.example.org/%20%20examples")}},
		{Name: "base-uri-26", XPath: "declare base-uri \"abc\"; fn:ends-with(fn:string(fn:static-base-uri()),\"abc\")", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-BaseURIProlog-1", XPath: `declare(::)base-uri(::)"http://example.com/declareBaseURITest"; 
        static-base-uri() eq 'http://example.com/declareBaseURITest'`, Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-BaseURIProlog-2", XPath: `declare(::)base-uri(::)"http://example.com/declareBaseURITest"; 
        declare(::)base-uri(::)"http://example.com/declareBaseURITest2"; 1 eq 1`, ExpectError: true},
		{Name: "K-BaseURIProlog-3", XPath: `declare(::)base-uri(::)"http://example.com/declareBaseURITest"(::); 
        declare(::)base-uri(::)"http://example.com/declareBaseURITest"(::); 1 eq 1`, ExpectError: true},
		{Name: "K2-BaseURIProlog-1", XPath: "declare base-uri \"http:\\\\invalid>URI\\someURI\"; 1", ExpectError: true},
		{Name: "K2-BaseURIProlog-2", XPath: "declare base-uri \"c:\\windows\"; 1", ExpectError: true},
		{Name: "K2-BaseURIProlog-3", XPath: "declare base-uri \"c:\\windows\"; fn:doc(\"example.com.xml\")", ExpectError: true},
		{Name: "K2-BaseURIProlog-4", XPath: "declare base-uri \"abc\"; declare function local:isAbsolute($uri as xs:string?) as xs:boolean { fn:matches($uri, \"[a-zA-Z0-9\\-.]*:/\") }; local:isAbsolute(fn:static-base-uri())", ExpectError: true},
		{Name: "K2-BaseURIProlog-5", XPath: "declare base-uri \"\"; ends-with(fn:static-base-uri(), \"prod/BaseURIDecl.xml\")", ExpectError: true},
		{Name: "K2-BaseURIProlog-7", XPath: "base-uri lt base-uri", ExpectError: true},
		{Name: "base-URI-modules-001", XPath: `declare base-uri "http://www.example.org/base1";
          import module namespace m ="http://www.w3.org/TestModules/module-001";
          static-base-uri() eq m:static-base-uri()`, Assertions: []qt3Assertion{qt3AssertFalse()}},
	})
}

