func TestQT3_prod_DecimalFormatDecl(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "decimal-format-01", XPath: `declare default decimal-format zero-digit="0" grouping-separator="," decimal-separator=".";
      	format-number(2392.14*36.58,'000,000.000000')`, Assertions: []qt3Assertion{qt3AssertStringValue("087,504.481200")}},
		{Name: "decimal-format-02", XPath: `declare default decimal-format digit="#" grouping-separator="," decimal-separator=".";
      	format-number(12792.14*96.58,'##,###,000.000###')`, Assertions: []qt3Assertion{qt3AssertStringValue("1,235,464.8812")}},
		{Name: "decimal-format-03", XPath: `declare default decimal-format minus-sign="-" grouping-separator="," decimal-separator=".";
      	format-number(2792.14*(-36.58),'000,000.000###')`, Assertions: []qt3Assertion{qt3AssertStringValue("-102,136.4812")}},
		{Name: "decimal-format-04", XPath: `declare default decimal-format minus-sign="-" pattern-separator=";" grouping-separator="," decimal-separator=".";
      	format-number(2392.14*(-36.58),'000,000.000###;###,###.000###')`, Assertions: []qt3Assertion{qt3AssertStringValue("87,504.4812")}},
		{Name: "decimal-format-05", XPath: `declare decimal-format local:df minus-sign="-" percent="%" decimal-separator=".";
      	format-number(0.4857,'###.###%', 'local:df')`, Assertions: []qt3Assertion{qt3AssertStringValue("48.57%")}},
		{Name: "decimal-format-06", XPath: `declare decimal-format local:df minus-sign="-" per-mille="‰" decimal-separator=".";
      	format-number(0.4857,'###.###‰')`, Assertions: []qt3Assertion{qt3AssertStringValue("485.7‰")}},
		{Name: "decimal-format-07", XPath: `declare decimal-format local:df minus-sign="-" currency-symbol="¤" decimal-separator=".";
      	format-number(95.4857,'¤###.####', "local:df")`, ExpectError: true},
		{Name: "decimal-format-09", XPath: `declare default decimal-format decimal-separator="|" grouping-separator="."; 
         format-number(931.4857,'000.000|###')`, Assertions: []qt3Assertion{qt3AssertStringValue("000.931|486")}},
		{Name: "decimal-format-11", XPath: `declare default decimal-format digit="!" pattern-separator="\";
        format-number(26931.4,'+!!!,!!!.!!!\-!!,!!!.!!!')`, Assertions: []qt3Assertion{qt3AssertStringValue("+26,931.4")}},
		{Name: "decimal-format-12", XPath: `declare default decimal-format digit="!" pattern-separator="\";
        format-number(-26931.4,'+!!,!!!.!!!\-!!!,!!!.!!!')`, Assertions: []qt3Assertion{qt3AssertStringValue("-26,931.4")}},
		{Name: "decimal-format-13", XPath: `declare default decimal-format digit="!" pattern-separator="\";
        format-number(-26931.4,'!!!,!!!.!!!')`, Assertions: []qt3Assertion{qt3AssertStringValue("-26,931.4")}},
		{Name: "decimal-format-14", XPath: `declare decimal-format local:df2 infinity="off-the-scale";
        format-number(1 div 0e0,'###############################', 'local:df2')`, Assertions: []qt3Assertion{qt3AssertStringValue("off-the-scale")}},
		{Name: "decimal-format-15", XPath: `declare decimal-format local:df2 NaN="non-numeric";
        format-number(number('none'), '#############', 'local:df2')`, Assertions: []qt3Assertion{qt3AssertStringValue("non-numeric")}},
		{Name: "decimal-format-16", XPath: `declare default decimal-format  per-mille="m";
        format-number(0.4857,'###.###m')`, Assertions: []qt3Assertion{qt3AssertStringValue("485.7m")}},
		{Name: "decimal-format-17", XPath: `declare default decimal-format  minus-sign="_";
        format-number(-26931.4,'+###,###.###;-###,###.###')`, Assertions: []qt3Assertion{qt3AssertStringValue("-26,931.4")}},
		{Name: "decimal-format-18", XPath: `declare default decimal-format minus-sign="_";
        format-number(-26931.4,'###,###.###')`, Assertions: []qt3Assertion{qt3AssertStringValue("_26,931.4")}},
		{Name: "decimal-format-19", XPath: `declare decimal-format myminus minus-sign="_"; 
        concat(format-number(-26931.4,'###,###.###','myminus'), '/',
        format-number(-42857.1,'###,###.###'))`, Assertions: []qt3Assertion{qt3AssertStringValue("_26,931.4/-42,857.1")}},
		{Name: "decimal-format-20", XPath: `declare namespace foo="http://foo.ns";
        declare decimal-format foo:decimal1  decimal-separator="!" grouping-separator="*";
        declare decimal-format decimal1  decimal-separator="*" grouping-separator="!";
        format-number(1234.567,'#*###*###!###','foo:decimal1')`, Assertions: []qt3Assertion{qt3AssertStringValue("1*234!567")}},
		{Name: "decimal-format-21", XPath: `import module namespace m="http://www.w3.org/TestModules/dfd-module-001";
        declare decimal-format df001 grouping-separator="!";
        format-number(123456.789,'#!###!###.###','df001')||'-'||m:do()`, Assertions: []qt3Assertion{qt3AssertStringValue("123!456.789-123'456.789")}},
		{Name: "decimal-format-31", XPath: `declare default decimal-format decimal-separator = "^";
        declare default decimal-format decimal-separator = "^";
      	true()`, ExpectError: true},
		{Name: "decimal-format-32", XPath: `declare decimal-format fmt1 decimal-separator = "^";
        declare decimal-format fmt1 decimal-separator = "^";
      	true()`, ExpectError: true},
		{Name: "decimal-format-33", XPath: `declare decimal-format fmt1 decimal-separator = "^";
        declare decimal-format fmt2 decimal-separator = "~";
      	concat (format-number(123.45, '9999^999', 'fmt1'), " and ",
                format-number(123.45, '9999~999', 'fmt2'))`, Assertions: []qt3Assertion{qt3AssertStringValue("0123^450 and 0123~450")}},
		{Name: "decimal-format-34", XPath: `declare default decimal-format decimal-separator = "^" grouping-separator = "\" decimal-separator = "^";
      	true()`, ExpectError: true},
		{Name: "decimal-format-35", XPath: `declare default decimal-format zero-digit = "A";
      	true()`, ExpectError: true},
		{Name: "decimal-format-36", XPath: `declare default decimal-format decimal-separator = "~" grouping-separator = "~";
      	true()`, ExpectError: true},
		{Name: "decimal-format-37", XPath: `declare default decimal-format decimal-separator = ",";
      	true()`, ExpectError: true},
		{Name: "decimal-format-38", XPath: `declare default decimal-format decimal-sprtr = ".";
      	true()`, ExpectError: true},
		{Name: "decimal-format-39", XPath: `declare default decimal-format minus-sign="-";
        format-number(-26931.4,'###,###.###')`, Assertions: []qt3Assertion{qt3AssertStringValue("-26,931.4")}},
		{Name: "decimal-format-40", XPath: `declare default decimal-format NaN = "0";
      format-number(xs:double('NaN'),'###,###.###')`, Assertions: []qt3Assertion{qt3AssertStringValue("0")}},
		{Name: "decimal-format-902err", XPath: `declare default decimal-format digit='$';
        format-number(931.4857,'000.$$0')`, ExpectError: true},
		{Name: "decimal-format-903err", XPath: `declare default decimal-format digit='$';
        declare default decimal-format minus-sign='_';
        format-number(931.4857,'000.$$0')`, ExpectError: true},
		{Name: "decimal-format-904err", XPath: `declare namespace a="http://a.com/";
        declare namespace b="http://a.com/";
        declare decimal-format a:one digit='$';
        declare decimal-format two digit='$';
        declare decimal-format three digit='$';
        declare decimal-format four digit='$';
        declare decimal-format five digit='$';
        declare decimal-format b:one minus-sign="_";
        declare default decimal-format minus-sign='_';
        format-number(931.4857,'000.$$0')`, ExpectError: true},
		{Name: "decimal-format-905err", XPath: `declare decimal-format q decimal-separator="." grouping-separator=",";
        format-number(931.4857,'fred.ginger', 'q')`, ExpectError: true},
		{Name: "decimal-format-906err", XPath: "format-number(931.45, '000.##0', 'foo:bar')", ExpectError: true},
		{Name: "decimal-format-907err", XPath: `declare namespace a="http://a.com/";
        declare namespace b="http://a.com/";
        declare decimal-format a:one digit='$' zero-digit="0" minus-sign="_" digit="#";
        format-number(931.4857,'000.$$0', 'a:one')`, ExpectError: true},
		{Name: "decimal-format-908err", XPath: `declare default decimal-format digit="one";
        format-number(931.4857,'000.$$0')`, ExpectError: true},
		{Name: "decimal-format-909err", XPath: `declare default decimal-format zero-digit="1";
        format-number(931.4857,'000.$$0')`, ExpectError: true},
		{Name: "decimal-format-910err", XPath: `declare default decimal-format zero-digit="a";
        format-number(931.4857,'aaa.$$a')`, ExpectError: true},
		{Name: "decimal-format-911err", XPath: `declare default decimal-format minus-sign="--";
        format-number(931.4857,'000.$$0')`, ExpectError: true},
		{Name: "decimal-format-912err", XPath: `declare default decimal-format decimal-separator = "6";
      true()`, ExpectError: true},
	})
}

