func TestQT3_prod_DirElemConstructor(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "K2-DirectConElem-54", XPath: "namespace-node {\"p\"} {\"abc\"}", ExpectError: true},
		{Name: "cbcl-directconelem-001", XPath: `declare default element namespace "http://example.com/0"; 
declare namespace a = "http://example.com/1"; 
declare namespace b = "http://example.com/2"; 
declare copy-namespaces preserve,no-inherit;

declare function local:in-scope-namespace-bindings($arg)
{
  for $i in in-scope-prefixes($arg) 
  order by $i 
  return 
  concat("xmlns",
         if (string-length($i) = 0)
         then ""
         else ":",
         $i,
         '="', namespace-uri-for-prefix($i, $arg), '"')
};

<a:outer b:outer="attr" xmlns:c="http://example.com/3" c:outer="attr">
  <inner a="a:attr" b="b:attr" />
</a:outer>/(local:in-scope-namespace-bindings(.),
            '|', 
            local:in-scope-namespace-bindings((./*)[1]))`, Assertions: []qt3Assertion{qt3AssertStringValue("xmlns:a=\"http://example.com/1\" xmlns:b=\"http://example.com/2\" xmlns:c=\"http://example.com/3\" xmlns:xml=\"http://www.w3.org/XML/1998/namespace\" | xmlns=\"http://example.com/0\" xmlns:c=\"http://example.com/3\" xmlns:xml=\"http://www.w3.org/XML/1998/namespace\"")}},
		{Name: "cbcl-directconelem-002", XPath: `declare default element namespace "http://example.com/0"; 
declare namespace a = "http://example.com/1"; 
declare namespace b = "http://example.com/2"; 
declare copy-namespaces preserve,inherit;

declare function local:in-scope-namespace-bindings($arg)
{
  for $i in in-scope-prefixes($arg) 
  order by $i 
  return 
  concat("xmlns",
         if (string-length($i) = 0)
         then ""
         else ":",
         $i,
         '="', namespace-uri-for-prefix($i, $arg), '"')
};

<a:outer b:outer="attr" xmlns:c="http://example.com/3" c:outer="attr">
  <inner a="a:attr" b="b:attr" />
</a:outer>/(local:in-scope-namespace-bindings(.),
            '|', 
            local:in-scope-namespace-bindings((./*)[1]))`, Assertions: []qt3Assertion{qt3AssertStringValue("xmlns:a=\"http://example.com/1\" xmlns:b=\"http://example.com/2\" xmlns:c=\"http://example.com/3\" xmlns:xml=\"http://www.w3.org/XML/1998/namespace\" | xmlns=\"http://example.com/0\" xmlns:c=\"http://example.com/3\" xmlns:xml=\"http://www.w3.org/XML/1998/namespace\"")}},
	})
}

