func TestQT3_prod_EmptyOrderDecl(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "emptyorderdecl-1", XPath: "declare default order empty least; declare default order empty greatest;  \"aaa\"", ExpectError: true},
		{Name: "emptyorderdecl-4", XPath: "declare default order empty greatest;  for $i in (1,4,0 div 0E0,7) order by $i ascending return $i", Assertions: []qt3Assertion{qt3AssertStringValue("1 4 7 NaN")}},
		{Name: "emptyorderdecl-5", XPath: "declare default order empty greatest;  for $i in (1,4,0 div 0E0,0 div 0E0,7) order by $i ascending return $i", Assertions: []qt3Assertion{qt3AssertStringValue("1 4 7 NaN NaN")}},
		{Name: "emptyorderdecl-8", XPath: "declare default order empty greatest;  for $i in (1,4,0 div 0E0,7) return $i", Assertions: []qt3Assertion{qt3AssertStringValue("1 4 NaN 7")}},
		{Name: "emptyorderdecl-9", XPath: "declare default order empty least;  for $i in (1,4,0 div 0E0,7) return $i", Assertions: []qt3Assertion{qt3AssertStringValue("1 4 NaN 7")}},
		{Name: "emptyorderdecl-12", XPath: "declare default order empty greatest;  for $i in (1,4,0 div 0E0,7) order by $i descending return $i", Assertions: []qt3Assertion{qt3AssertStringValue("NaN 7 4 1")}},
		{Name: "emptyorderdecl-13", XPath: "declare default order empty greatest;  for $i in (1,4,0 div 0E0,0 div 0E0,7) order by $i descending return $i", Assertions: []qt3Assertion{qt3AssertStringValue("NaN NaN 7 4 1")}},
		{Name: "emptyorderdecl-16", XPath: "declare default order empty least;  for $i in (1,4,0 div 0E0,7) order by $i ascending return $i", Assertions: []qt3Assertion{qt3AssertStringValue("NaN 1 4 7")}},
		{Name: "emptyorderdecl-17", XPath: "declare default order empty least;  for $i in (1,4,0 div 0E0,0 div 0E0,7) order by $i ascending return $i", Assertions: []qt3Assertion{qt3AssertStringValue("NaN NaN 1 4 7")}},
		{Name: "emptyorderdecl-20", XPath: "declare default order empty least;  for $i in (1,4,0 div 0E0,7) order by $i descending return $i", Assertions: []qt3Assertion{qt3AssertStringValue("7 4 1 NaN")}},
		{Name: "emptyorderdecl-21", XPath: "declare default order empty least;  for $i in (1,4,0 div 0E0,0 div 0E0,7) order by $i descending return $i", Assertions: []qt3Assertion{qt3AssertStringValue("7 4 1 NaN NaN")}},
		{Name: "emptyorderdecl-23", XPath: "declare default order empty greatest;  for $i in (1,4,3,0 div 0E0,7) order by $i ascending empty least return $i", Assertions: []qt3Assertion{qt3AssertStringValue("NaN 1 3 4 7")}},
		{Name: "emptyorderdecl-25", XPath: "declare default order empty greatest;  for $i in (1,4,3,0 div 0E0,7) order by $i ascending empty greatest return $i", Assertions: []qt3Assertion{qt3AssertStringValue("1 3 4 7 NaN")}},
		{Name: "emptyorderdecl-27", XPath: "declare default order empty least;  for $i in (1,4,3,0 div 0E0,7) order by $i ascending empty greatest return $i", Assertions: []qt3Assertion{qt3AssertStringValue("1 3 4 7 NaN")}},
		{Name: "emptyorderdecl-29", XPath: "declare default order empty least;  for $i in (1,4,3,0 div 0E0,7) order by $i ascending empty least return $i", Assertions: []qt3Assertion{qt3AssertStringValue("NaN 1 3 4 7")}},
		{Name: "K-EmptyOrderProlog-1", XPath: "declare(::)default order empty(::)greatest; 1 eq 1", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-EmptyOrderProlog-2", XPath: "declare(::)default order empty(::)least; 1 eq 1", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "K-EmptyOrderProlog-3", XPath: "declare(::)default order empty(::)greatest; declare(::)default order empty(::)least; 1 eq 1", ExpectError: true},
	})
}

