func TestQT3_prod_FLWORExpr_static_typing(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "statictyping-21", XPath: "let $x := 1 let $z := $x + $y return $x", ExpectError: true},
		{Name: "statictyping-22", XPath: "declare variable $x := $y + 1; \"abc\"", ExpectError: true},
		{Name: "statictyping-23", XPath: "for $x in (1, 2, 3) for $z in ($x, $y) return $x", ExpectError: true},
		{Name: "statictyping-24", XPath: "let $var := (\"a\",\"b\",\"c\") where fn:not($var) eq fn:true() return $var", ExpectError: true},
		{Name: "ST-WhereExpr001", XPath: "for $file in (//Folder)[1]/File where ($file, 1) return $file/FileName", DocPath: "prod/ForClause/fsx.xml", ExpectError: true},
		{Name: "ST-WhereExpr002", XPath: "for $file in (//Folder)[1]/File where (1, $file) return $file/FileName", DocPath: "prod/ForClause/fsx.xml", ExpectError: true},
		{Name: "statictyping-1", XPath: "for $var in (\"a\",\"b\",\"c\") where $var + 1 = 3 return $var", ExpectError: true},
		{Name: "statictyping-2", XPath: "for $var in (\"a\",\"b\",\"c\") where fn:abs(($var)) return $var", ExpectError: true},
		{Name: "statictyping-3", XPath: "for $var in (\"a\",\"b\",\"c\") where fn:avg(($var,1)) return $var", ExpectError: true},
		{Name: "statictyping-4", XPath: "for $var in (\"a\",\"b\",\"c\") where fn:max(($var,1)) return $var", ExpectError: true},
		{Name: "statictyping-5", XPath: "for $var in (\"a\",\"b\",\"c\") where fn:min(($var,1)) return $var", ExpectError: true},
		{Name: "statictyping-6", XPath: "for $var in (\"a\",\"b\",\"c\") where fn:sum(($var,1)) return $var", ExpectError: true},
		{Name: "statictyping-7", XPath: "let $var := (\"a\",\"b\",\"c\") where fn:boolean($var) = fn:true() return $var", ExpectError: true},
		{Name: "statictyping-8", XPath: "for $var in (\"a\",\"b\",\"c\") where ($var - 1) = 3 return $var", ExpectError: true},
		{Name: "statictyping-9", XPath: "for $var in (\"a\",\"b\",\"c\") where ($var * 1) = 3 return $var", ExpectError: true},
		{Name: "statictyping-10", XPath: "for $var in (\"a\",\"b\",\"c\") where ($var div 2) = 3 return $var", ExpectError: true},
		{Name: "statictyping-11", XPath: "for $var in (\"a\",\"b\",\"c\") where ($var idiv 2) = 3 return $var", ExpectError: true},
		{Name: "statictyping-12", XPath: "for $var in (\"a\",\"b\",\"c\") where ($var mod 2) = 3 return $var", ExpectError: true},
		{Name: "statictyping-13", XPath: "let $var := (\"a\",\"b\",\"c\") where ($var eq 1) return $var", ExpectError: true},
		{Name: "statictyping-14", XPath: "let $var := (\"a\",\"b\",\"c\") where ($var le 1) return $var", ExpectError: true},
		{Name: "statictyping-15", XPath: "let $var := (\"a\",\"b\",\"c\") where ($var lt 1) return $var", ExpectError: true},
		{Name: "statictyping-16", XPath: "let $var := (\"a\",\"b\",\"c\") where ($var gt 1) return $var", ExpectError: true},
		{Name: "statictyping-17", XPath: "let $var := (\"a\",\"b\",\"c\") where ($var ne 1) return $var", ExpectError: true},
		{Name: "statictyping-18", XPath: "let $var := (1,2,3) where ($var + 1) return $var", ExpectError: true},
		{Name: "statictyping-19", XPath: "let $var := (1,2,3) where ($var - 1) return $var", ExpectError: true},
		{Name: "statictyping-20", XPath: "let $var := (1,2,3) where ($var * 1) return $var", ExpectError: true},
		{Name: "ST-PITest-01", XPath: "(: Description: In LetClause, binding expr's ST must be subtype of variable's ST. Under REC FS, both are 'processing-instruction?', so STA succeeds. Under PER FS, former is 'processing-instruction filesystem?', latter is 'processing-instruction filesytem', so STA fails, raises error. (Note that an implementation that doesn't do STA will not raise an error.) :) let $pi as processing-instruction(filesystem) := (//processing-instruction(filesystem))[1] return $pi", DocPath: "prod/ForClause/fsx_NS.xml", ExpectError: true},
		{Name: "ST-PITest-02", XPath: `for $pi in //processing-instruction(nonexistent) 
        let $pi2 as processing-instruction(filesystem) := $pi 
        return $pi2`, DocPath: "prod/ForClause/fsx_NS.xml", ExpectError: true},
	})
}

