func TestQT3_prod_InlineFunctionExpr(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "inline-fn-001", XPath: "let $f := function($x){$x+1} return $f(2)", Assertions: []qt3Assertion{qt3AssertEq("3")}},
		{Name: "inline-fn-002", XPath: "let $pi := function(){3.14159} return $pi()", Assertions: []qt3Assertion{qt3AssertEq("3.14159")}},
		{Name: "inline-fn-003", XPath: "let $add := function($x, $y){$x + $y} return $add(4, 2)", Assertions: []qt3Assertion{qt3AssertEq("6")}},
		{Name: "inline-fn-004", XPath: `sum(for $i in 1 to 6 return
             let $add := function($x){$x + $i} return $add(4))`, Assertions: []qt3Assertion{qt3AssertEq("45")}},
		{Name: "inline-fn-005", XPath: `(1 to 4) !
         (let $add := function($x){$x + .} return $add(4))`, ExpectError: true},
		{Name: "inline-fn-006", XPath: "let $void := function(){} return $void()", ExpectError: true},
		{Name: "inline-fn-007", XPath: "let $void := function(){} return $void()", Assertions: []qt3Assertion{qt3AssertEmpty()}},
		{Name: "inline-fn-008", XPath: `let $outer := function($x) {
            let $inner := function($y) {$y + $x}
            return $inner(5)
         }
         return $outer(3)`, Assertions: []qt3Assertion{qt3AssertEq("8")}},
		{Name: "inline-fn-009", XPath: `let $bonus := 10,
             $outer := function($x) {
                let $inner := function($y) {$y + $x + $bonus}
                return $inner(5)
             }
         return $outer(3)`, Assertions: []qt3Assertion{qt3AssertEq("18")}},
		{Name: "inline-fn-010", XPath: `let $add := function($x as xs:integer, $y as xs:integer){$x + $y}
         return $add(3,4)`, Assertions: []qt3Assertion{qt3AssertEq("7")}},
		{Name: "inline-fn-011", XPath: `let $add := function($x as xs:integer, $y as xs:integer){$x + $y}
         return $add(3,4.2)`, ExpectError: true},
		{Name: "inline-fn-012", XPath: `let $add := function($x, $y) as xs:integer {$x + $y}
         return $add(3, 4)`, Assertions: []qt3Assertion{qt3AssertEq("7")}},
		{Name: "inline-fn-012a", XPath: `let $add := function($x, $y) as xs:integer {$x + $y}
         return $add(3, 4.1)`, ExpectError: true},
		{Name: "inline-fn-013", XPath: `let $add := function($x, $y) as xs:double {$x + $y}
         return $add(3, 4)`, Assertions: []qt3Assertion{qt3AssertEq("7"), qt3AssertType("xs:double")}},
		{Name: "inline-fn-014", XPath: `let $process := function($op, $x, $y) as function(*) {if ($op = "+") then function() {$x + $y} else function() {$x - $y}}
         return $process("+", 3, 4)()`, Assertions: []qt3Assertion{qt3AssertEq("7")}},
		{Name: "inline-fn-016", XPath: "let $add := %Q{http://example.com/speed}fast %Q{http://example.com/origin}author(\"Mike\") function($x, $y) {$x + $y} return $add(2,2)", ExpectError: true},
		{Name: "inline-fn-021", XPath: "let $add := function($x, $y) {$x + $y} return function-name($add)", Assertions: []qt3Assertion{qt3AssertEmpty()}},
		{Name: "inline-fn-022", XPath: "let $add := function($x, $y) {$x + $y} return function-arity($add)", Assertions: []qt3Assertion{qt3AssertEq("2")}},
		{Name: "inline-fn-023", XPath: "let $add := function($x, $y) {$x + $y} return apply($add, [12, 5])", Assertions: []qt3Assertion{qt3AssertEq("17")}},
		{Name: "inline-fn-024", XPath: "function($x, $y) {$x + $y} (12, 5)", Assertions: []qt3Assertion{qt3AssertEq("17")}},
		{Name: "inline-fn-025", XPath: "function($x, $y) {$x + $y} [function-arity(.) = 2] (12, 5)", Assertions: []qt3Assertion{qt3AssertEq("17")}},
		{Name: "inline-fn-026", XPath: `let $weirdo := function($x, $f) {if ($x=0) then 0 else $f($x - 1, $f)} 
         return $weirdo(12, $weirdo)`, Assertions: []qt3Assertion{qt3AssertEq("0")}},
		{Name: "inline-fn-027", XPath: `let $calc := map{
            "+" : function($a, $b) {$a + $b},
            "-" : function($a, $b) {$a - $b},
            "*" : function($a, $b) {$a * $b},
            "/" : function($a, $b) {$a div $b}}
         return $calc("*")(2,3)`, Assertions: []qt3Assertion{qt3AssertEq("6")}},
		{Name: "inline-fn-028", XPath: "string(function($a, $b) {$a + $b})", ExpectError: true},
		{Name: "inline-fn-029", XPath: "deep-equal(function($a, $b) {$a + $b}, function($a, $b) {$a - $b})", ExpectError: true},
		{Name: "inline-fn-030", XPath: "data(function($a, $b) {$a + $b})", ExpectError: true},
		{Name: "inline-fn-031", XPath: `let $x := function($a, $b) {$a + $b}, 
             $y := function($a, $b) {$a - $b},
             $c := function($x, $y) {$x = $y}
         return $c($x, $y)`, ExpectError: true},
		{Name: "inline-fn-032", XPath: "function($a, $b) {$a + $b}", Assertions: []qt3Assertion{qt3AssertType("item()"), qt3AssertType("function(*)"), qt3AssertType("function(item()*, item()*) as item()*"), qt3AssertType("function(xs:integer, xs:integer) as item()*"), qt3AssertSkip(), qt3AssertSkip()}},
		{Name: "inline-fn-033", XPath: "function($a as xs:integer, $b as xs:integer) as xs:integer {$a + $b}", Assertions: []qt3Assertion{qt3AssertType("item()"), qt3AssertType("function(*)"), qt3AssertType("function(xs:integer, xs:integer) as item()*"), qt3AssertType("function(xs:long, xs:long) as xs:integer+"), qt3AssertSkip(), qt3AssertSkip()}},
		{Name: "inline-fn-036", XPath: `let $f := function($x as xs:double) {1 to $x}
         return $f(3)`, ExpectError: true},
	})
}

