func TestQT3_prod_SequenceType(t *testing.T) {
	t.Parallel()
	qt3RunTests(t, []qt3Test{
		{Name: "sequence-type-1", XPath: "(1,2,3) instance of xs:integer*", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "sequence-type-2", XPath: "(1E3,2E3,3E3) instance of xs:double*", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "sequence-type-3", XPath: "(1.1,3.2,4.5) instance of xs:decimal*", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "sequence-type-4", XPath: "(\"ab\",\"cde\",\"fgh\") instance of xs:string*", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "sequence-type-5", XPath: "(\"ab\",\"cde\",\"fgh\") instance of xs:integer*", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "sequence-type-6", XPath: "(1) instance of xs:integer?", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "sequence-type-7", XPath: "(1,2) instance of xs:integer?", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "sequence-type-8", XPath: "(1,2) instance of xs:integer+", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "sequence-type-9", XPath: "(2) castable as xs:integer?", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "sequence-type-10", XPath: "(1,2) castable as xs:integer?", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "sequence-type-11", XPath: "(1E3) castable as xs:double?", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "sequence-type-12", XPath: "(1E3,2E3) castable as xs:double?", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "sequence-type-13", XPath: "(1.2) castable as xs:decimal?", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "sequence-type-14", XPath: "(1.2,2.1) castable as xs:decimal?", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "sequence-type-15", XPath: "(\"abc\") castable as xs:string?", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "sequence-type-16", XPath: "(\"abc\",\"def\") castable as xs:string?", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "sequence-type-17", XPath: "(\"abc\") castable as xs:integer?", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "sequence-type-18", XPath: "(\"abc\",\"def\") castable as xs:integer?", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "sequence-type-19", XPath: "(fn:true(),fn:false()) instance of xs:boolean*", Assertions: []qt3Assertion{qt3AssertTrue()}},
		{Name: "sequence-type-20", XPath: "(fn:true(),fn:false()) instance of xs:boolean?", Assertions: []qt3Assertion{qt3AssertFalse()}},
		{Name: "sequence-type-21", XPath: "(fn:true(),fn:false()) instance of xs:boolean+", Assertions: []qt3Assertion{qt3AssertTrue()}},
	})
}

